const prompt = require("prompt-sync")();

// 함수 : 특정 작업을 반복하거나 재사용할 수 있도록 작성된 코드 블록 입니다.
// 자바스크립트 함수는 입력값(매개변수)을 받아 결과값을 반환(return) 함
// 함수의 주요 기능
// ┗ 입력값 검증 및 오류 처리
// ┗ 지역 스코프를 활용해 전역 변수 오염 방지
// ┗ 비동기 작업에 콜백 함수 아용 가능

// 자바스크립트 함수의 종류
// ┗ 함수 선언문 : funcion
// ┗ 호이스팅이 일어남
// console.log(sum(100, 300));

function sum(a, b) {
  return a + b;
}

// 함수 표현식 : 변수에 익명 함수를 할당하는 방식
// 호이스팅 되지 않음
// console.log(multiply(100, 200));
const multiply = function (a, b) {
  return a * b;
}
// 자바스크립트 함수의 종류
// ┗ 함수 선언문 : function
// ┗ 함수 표현식
// ┗ 화살표 함수
// ┗ 즉시 실행 함수
// ┗ 생성자 함수
// ┗ 콜백 함수
// ┗ 클로저

// 입력 받은 정수보다 미만의 소수의 합을 구하는 함수를 만드세요.
// ┗ 예) 12이면 2+3+5+7+11 = 28
// ┗ 소수란 1과 자기 자신 이외의 자연수로 나눌 수 없는 1보다 큰 자연수
// 함수 선언문과 함수 표현식으로 구현 해보기

// 소수 판별 함수 (선언문)
function isPrime(n) {
  if (n < 2) return false; // 2 미만은 소수가 아님
  for (let i = 2; i < n; i++) { // 2부터 n-1까지 순회
    if (n % i === 0) return false; // 나누어 떨어지면 소수 아님
  }
  return true; // 끝까지 나누어지지 않으면 소수
}

// 소수의 합을 구하는 함수 (선언문)
function sumPrime(n) {
  let sum = 0; // 합계 초기값
  for (let i = 2; i < n; i++) { // 2부터 n 미만까지 순회
    if (isPrime(i)) sum += i; // 소수이면 합계에 누적
  }
  return sum; // 최종 합계 반환
}

// 소수 판별 함수 (표현식)
const isPrimeExpr = function (n) {
  if (n < 2) return false; // 2 미만은 소수가 아님
  for (let i = 2; i < n; i++) { // 2부터 n-1까지 순회
    if (n % i === 0) return false; // 나누어 떨어지면 소수 아님
  }
  return true; // 끝까지 나누어지지 않으면 소수
}

// 소수의 합을 구하는 함수 (표현식)
const sumPrimeExpr = function (n) {
  let sum = 0; // 합계 초기값
  for (let i = 2; i < n; i++) { // 2부터 n 미만까지 순회
    if (isPrimeExpr(i)) sum += i; // 소수이면 합계에 누적
  }
  return sum; // 최종 합계 반환
}

const input = Number(prompt("정수 입력 : ")); // 문자열 입력을 숫자로 변환
console.log("함수 선언문 결과 : " + sumPrime(input)); // 선언문 버전 실행
console.log("함수 표현식 결과 : " + sumPrimeExpr(input)); // 표현식 버전 실행